use std::io;

fn gcd(u: u32, v: u32) -> u32 {
    if u == 0 {
        return u;
    }
    if v == 0 {
        return v;
    }
    let mut shift = 0;
    let mut aux : [u32; 2] = [(u | v), 1];
    while aux[0] & aux[1] == 0 {
        shift += 1;
        aux[1] <<= 1;
    }
    let mut u = u >> shift;
    let mut v = v >> shift;

    while u & 1 == 0 {
        u >>= 1;
    }

    loop {
        while v & 1 == 0 {
            v >>= 1;
        }

        if u > v {
            aux[0] = v;
            v = u;
            u = aux[0];
        }
        v = v - u;

        if v == 0 {
            break;
        }
    }
    u << shift
}

fn main() {
    let mut buffer = String::new();
    io::stdin().read_line(&mut buffer).expect("failed to read input");
    let n: u32 = buffer.trim().parse().expect("invalid input");

    let mut i = n / 2 + 1;
    while gcd(i, n - i) != 1 {
        i += 1;
    }
    println!("{} {}", n - i, i);
}
